import React, { useEffect, useRef, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getMovie } from '../services/api';
import videojs from 'video.js';
import 'video.js/dist/video-js.css';

const Player = () => {
  const { id } = useParams();
  const videoRef = useRef(null);
  const playerRef = useRef(null);
  const [movie, setMovie] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadMovie();
  }, [id]);

  const loadMovie = async () => {
    try {
      console.log('🎬 Cargando película ID:', id);
      const movieData = await getMovie(id);
      console.log('📽️ Película cargada:', movieData);
      setMovie(movieData);

      if (movieData.streams && movieData.streams.length > 0) {
        const videoSrc = movieData.streams[0].url;
        console.log('🎥 URL del video:', videoSrc);

        if (videoRef.current && !playerRef.current) {
          playerRef.current = videojs(videoRef.current, {
            controls: true,
            responsive: true,
            fluid: true,
            sources: [{
              src: videoSrc,
              type: 'application/x-mpegURL'
            }]
          });
        }
      }
    } catch (error) {
      console.error('❌ Error cargando película:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    return () => {
      if (playerRef.current) {
        playerRef.current.dispose();
        playerRef.current = null;
      }
    };
  }, []);

  if (loading) return <div className="p-4 text-white">Cargando...</div>;
  if (!movie) return <div className="p-4 text-white">Película no encontrada</div>;

  return (
    <div className="p-4 bg-black min-h-screen">
      <h1 className="text-white text-2xl mb-4">{movie.title}</h1>
      <video
        ref={videoRef}
        className="video-js vjs-default-skin w-full"
        controls
        preload="auto"
        data-setup="{}"
      />
    </div>
  );
};

export default Player;
